import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(pos1, pos2, truck_speed):
        distance = np.linalg.norm(pos1 - pos2)
        travel_time = distance / truck_speed
        return max(travel_time, 0)

    def calculate_penalty(window_end, current_time):
        return max(window_end - current_time, 0)

    shortest_time = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        arrival_time = current_time + calculate_distance(cur_truck_pos, customer_pos, truck_speed)

        if time_windows[idx] is not None:
            penalty = calculate_penalty(time_windows[idx][1], arrival_time)
            waiting_time = max(time_windows[idx][0] - arrival_time, 0)
            total_time = arrival_time + max(penalty, waiting_time)
        else:
            total_time = arrival_time

        if total_time < shortest_time:
            shortest_time = total_time
            best_node = idx

    return best_node
